(()=>{var e={};e.id=308,e.ids=[308],e.modules={2934:e=>{"use strict";e.exports=require("next/dist/client/components/action-async-storage.external.js")},4580:e=>{"use strict";e.exports=require("next/dist/client/components/request-async-storage.external.js")},5869:e=>{"use strict";e.exports=require("next/dist/client/components/static-generation-async-storage.external.js")},399:e=>{"use strict";e.exports=require("next/dist/compiled/next-server/app-page.runtime.prod.js")},5315:e=>{"use strict";e.exports=require("path")},7360:e=>{"use strict";e.exports=require("url")},7006:(e,t,n)=>{"use strict";n.r(t),n.d(t,{GlobalError:()=>s.a,__next_app__:()=>p,originalPathname:()=>c,pages:()=>h,routeModule:()=>g,tree:()=>d}),n(7004),n(7445),n(5866);var a=n(3191),o=n(8716),i=n(7922),s=n.n(i),r=n(5231),l={};for(let e in r)0>["default","tree","pages","GlobalError","originalPathname","__next_app__","routeModule"].indexOf(e)&&(l[e]=()=>r[e]);n.d(t,l);let d=["",{children:["blog",{children:["[slug]",{children:["__PAGE__",{},{page:[()=>Promise.resolve().then(n.bind(n,7004)),"/home/abmoallim/Documents/abmoallim/app/blog/[slug]/page.js"]}]},{}]},{metadata:{icon:[async e=>(await Promise.resolve().then(n.bind(n,7481))).default(e),async e=>(await Promise.resolve().then(n.bind(n,4998))).default(e)],apple:[],openGraph:[],twitter:[],manifest:void 0}}]},{layout:[()=>Promise.resolve().then(n.bind(n,7445)),"/home/abmoallim/Documents/abmoallim/app/layout.js"],"not-found":[()=>Promise.resolve().then(n.t.bind(n,5866,23)),"next/dist/client/components/not-found-error"],metadata:{icon:[async e=>(await Promise.resolve().then(n.bind(n,7481))).default(e),async e=>(await Promise.resolve().then(n.bind(n,4998))).default(e)],apple:[],openGraph:[],twitter:[],manifest:void 0}}],h=["/home/abmoallim/Documents/abmoallim/app/blog/[slug]/page.js"],c="/blog/[slug]/page",p={require:n,loadChunk:()=>Promise.resolve()},g=new a.AppPageRouteModule({definition:{kind:o.x.APP_PAGE,page:"/blog/[slug]/page",pathname:"/blog/[slug]",bundlePath:"",filename:"",appPaths:[]},userland:{loaderTree:d}})},2311:(e,t,n)=>{Promise.resolve().then(n.t.bind(n,9404,23))},7004:(e,t,n)=>{"use strict";n.r(t),n.d(t,{default:()=>r,generateStaticParams:()=>s});var a=n(9510),o=n(7371);let i=[{slug:"2025-what-actually-happened",frontmatter:{title:"2025: What Actually Happened",date:"2025-12-21",readingTime:"3 min read"},contentHtml:"<h1>2025: What Actually Happened</h1>\n<p>At the start of 2025, I had a clear list of goals. Not the loud kind the quiet, personal ones. They came from a year of learning, trying, failing, and slowly understanding myself better.</p>\n<p>Now that the year is coming to an end, I want to talk about what actually happened not what looks good on paper, but what stayed.</p>\n<h2>Learning to Say “No”</h2>\n<p>This one happened. Fully.</p>\n<p>I cut a lot of noise from my life this year. Projects, conversations, expectations even people. Not out of arrogance or bitterness, but out of clarity. I learned that saying “yes” to everything was slowly saying “no” to myself.</p>\n<p>Life got quieter. And better.</p>\n<h2>Financial Discipline</h2>\n<p>I didn’t suddenly become rich, but I became intentional.</p>\n<p>I managed my income more carefully, avoided unnecessary spending, and focused on stability over impulse. That alone reduced a lot of mental stress. Money stopped being something I reacted to and started being something I planned around.</p>\n<p>That shift mattered more than I expected.</p>\n<h2>AI Agents (Expectation vs Reality)</h2>\n<p>I didn’t go as deep into AI agentics as I thought I would.</p>\n<p>But I also didn’t do nothing.</p>\n<p>I built a few agents, experimented, learned the patterns, and understood the limitations. None of them reached production level and I’m okay with that. The learning still happened, just not in the dramatic way I imagined at the start of the year.</p>\n<p>The highlight was the time invested with a friend: we clocked more than 120 focused hours across different agentic projects and we’re currently building <strong>Decisionfy</strong> together. Sometimes progress is quieter than ambition.</p>\n<h2>Lama Tools</h2>\n<p>This was one of the highlights of 2025.</p>\n<p>We delivered seven solid projects, including two AI-enabled semi-ERP systems. Real clients. Real delivery. Real responsibility.</p>\n<p>We may not have hit every financial milestone yet, but Lama Tools moved from “potential” to proven execution and that matters far more in the long run.</p>\n<h2>Living on My Own Terms</h2>\n<p>Alhamdulillah, this one runs deep.</p>\n<p>I’ve made peace with who I am, how I work, and what I value. I no longer feel the need to match timelines, expectations, or definitions of success that don’t belong to me.</p>\n<p>That internal peace is something I don’t take lightly.</p>\n<h2>Content Creation (An Honest Take)</h2>\n<p>I tried.</p>\n<p>I really did.</p>\n<p>And I realized something important, maybe content creation just isn’t for me or at least not right now. I didn’t enjoy it enough. I didn’t want it badly enough. So I stopped forcing it.</p>\n<p>That felt like growth too.</p>\n<h2>Small but Meaningful Tech Shifts</h2>\n<p>This year also had its fun, nerdy transitions:</p>\n<ul>\n<li>Windows → Linux (Fedora) and I’m genuinely enjoying it</li>\n<li>Cursor → Windsurf</li>\n<li>OpenAI → Claude</li>\n<li>pip → uv</li>\n<li>Vercel → Cloudflare</li>\n<li>Chrome → Brave</li>\n</ul>\n<p>Nothing life-changing on its own, but together they reflect a pattern: choosing tools that feel intentional, minimal, and aligned with how I want to work.</p>\n<h2>The Biggest Achievement</h2>\n<p>This is the one that outweighs everything else.</p>\n<p>With the help of my sisters and cousin, I managed to move my family from Mogadishu to Kenya.</p>\n<p>No project, no revenue milestone, no technical win comes close to that.</p>\n<p>It was stressful. Heavy. Expensive. Emotional. But it was worth it.</p>\n<p>Alhamdulillah.</p>\n<h2>One More Thing</h2>\n<p>I also spent time learning day trading in a halal way. Not chasing hype, but understanding markets, discipline, risk, and patience. Whether it becomes a long-term path or not, the learning itself has already paid off.</p>\n<p>2025 wasn’t flashy.</p>\n<p>It wasn’t viral.</p>\n<p>It wasn’t loud.</p>\n<p>But it was foundational.</p>\n<p>And I’m walking into the next year calmer, clearer, and more grounded than I’ve ever been.</p>\n<p>That’s enough for now.</p>\n"},{slug:"i-loved-cursor-pro-until-the-credits-changed",frontmatter:{title:"I Loved Cursor Pro Until the Credits Changed",date:"2025-08-17",readingTime:"7 min read"},contentHtml:'<h1>I Loved Cursor Pro Until the Credits Changed</h1>\n<p>When AI coding assistants started getting useful, I was one of those people who jumped in fast. I’m a software engineer who works on web tech by day and spins up side projects and freelance work on nights and weekends. There’s always more to do than hours in the day, and anything that speeds up development, testing, or just getting a proof-of-concept out the door is immediately interesting to me.</p>\n<p>My journey started with ChatGPT, great ideas, but I hit context limits and half-finished pages all the time. I’d get a chunk of code, it would cut off in the middle of a bracket, and the “continue” dance would sometimes lose the thread. I tried GitHub Copilot but felt like I wasn’t getting the most out of it. It behaved like a completion tool, not a partner. Then I discovered Sourcegraph’s Cody in VS Code and thought, “Okay, this is magic.” It was free but limited. I wanted more.</p>\n<p>That’s when I tried Cursor.</p>\n<hr>\n<h2>Falling for the Features</h2>\n<p>Cursor’s free plan (50 requests/Month) was enough to hook me. When I came back to coding after a short break I started paying for Pro, and for the first few months I was experimenting non-stop, adding documentation, libraries and resources to cursor, letting agents apply fixes to files, creating files without me telling them line by line. At times it felt like Cursor was doing the boring, repetitive work I hate, leaving me to the parts of engineering I actually enjoy.</p>\n<p>I recommended it to friends and family. I got three people to sign up and start paying. The product met my expectations, then some. When they released agents that could apply code directly to your files, create new files, and automate parts of workflows, I was genuinely impressed.</p>\n<hr>\n<h2>The One Thing That Changed Everything: Credits and Pricing</h2>\n<p>This is where things went sideways for me. For months the $20 Pro plan and the way usage was shown in the dashboard made sense, you had a simple “credits” view and you could see how many you’ve used. It was predictable, and it let me recommend the product confidently.</p>\n<p>Recently they changed how included usage is handled and how it’s displayed. The $20 price stayed the same, but the effective amount of usage you get per month (how many requests you can make on various models) got smaller for some models, and the dashboard now shows token counts and lines of code rather than the simple credits view I was used to. The docs even list rough equivalencies (for example, Pro being roughly ~550 Gemini requests or ~225 Sonnet 4 requests, and different included usage for higher tiers). <a href="https://docs.cursor.com/en/account/pricing">See Cursor’s pricing here</a>.</p>\n<p>There are a few specifics that bothered me:</p>\n<ul>\n<li>The limits feel more granular and more confusing now. It’s split by model, and if you use up your allocation on one model (say Claude 4) it can block other models even though you haven’t “used more” overall in the way you used to.</li>\n<li>The dashboard switches from “credits left” to “tokens and lines” which is less intuitive when you’ve been tracking a credits balance for months.</li>\n<li>The “Auto” model selection used to be reliable for me. Now it feels like it switches to models that give far fewer usable requests, and if you’re used to the pro models, Auto isn’t a great fallback.</li>\n<li>Practically, my billing cycle started on the 9th of the month and by the 16th I was already at my limit. I hadn’t increased my usage, nothing about my workflow changed, but I hit the cap much earlier than before.</li>\n</ul>\n<p>Look, I get it, new, bigger models cost more to run and companies need to balance product quality with sustainability. I’m not outraged about the need to adjust pricing. I am, however, frustrated by the opaque way the change affects real-world usage and recommendations. When I was telling people “$20 gets you 500 credits and you’re fine,” that was an easy sell. Now it isn’t.</p>\n<hr>\n<h2>Bugs and Other Niggles (Not the Reason I’m Leaving)</h2>\n<p>To be clear, this isn’t a story about buggy software. There are a few bugs, but nothing that would make me leave on its own. The UX around usage and the pricing model is the real problem for me. If Cursor fixed the usage display, made the model-usage rules easier to understand, or rebalanced how included usage maps to the newer models, I’d be back in a heartbeat. I mean it: I love the product.</p>\n<hr>\n<h2>So I’m Trying Windsurf</h2>\n<p>Because of the credit changes and the dashboard confusion, I’m switching to <strong>Windsurf</strong>. They are offering what Cursor originally did, 500 requests for a fixed price. It’s simple and predictable, and that’s exactly what I need when coding for my job, side projects, and freelance clients. <a href="https://windsurf.com/pricing">See Windsurf’s pricing here</a>.</p>\n<p>Would I recommend Cursor today? Not as-is. Would I recommend it to certain people? Maybe, if you’re curious and don’t mind crunching numbers and monitoring usage closely, it might still be a good fit. But for now, when someone asks me “is Cursor Pro worth it?” my answer is it was absolutely worth it for me for nine months, but with the current pricing and usage model I can’t recommend it to people who want a predictable, hands-off experience.</p>\n<hr>\n<h2>Closing: A Love Letter, But Conditional</h2>\n<p>I’m not writing this as a burn notice. Cursor did a lot of things right and it helped me ship more and worry less for months. This is more of a frustrated love letter: I want Cursor to work, and I’d happily come back if the team made the usage model simpler and gave more predictable included usage for those of us who rely on it day to day.</p>\n<p>If you’re a developer thinking about Cursor, try it, see how it fits your workflow, and pay close attention to the dashboard and which models you pick. If you’re a product person at Cursor reading this,please make the included usage easier to understand and make Auto behave like the “pro” Auto that used to feel like a safe middle ground.</p>\n'},{slug:"my-2024",frontmatter:{title:"Reflecting on My 2024",date:"2024-12-13",readingTime:"5 min read"},contentHtml:'<h1>Growth, Resilience, and New Beginnings</h1>\n<p>2024 was a year that pushed me to my limits, both personally and professionally. It wasn’t a smooth ride, it was a year filled with ambitious projects, hard decisions, tough lessons, and valuable growth. Despite the challenges, it became a defining year of transformation, setting the foundation for an exciting future.</p>\n<hr>\n<h2>The Year Began with Bold Goals</h2>\n<p>At the start of 2024, I was focused on building solutions that made an impact. One of the projects closest to my heart was <strong>InterviewWay</strong>, a startup idea aimed at helping individuals prepare for interviews and assessments. While the idea showed promise, I decided to put it on hold to focus on other pressing opportunities.</p>\n<hr>\n<h2>Headstarter: A Season of Intense Learning</h2>\n<p>Midway through the year, I joined the <strong>Headstarter program</strong>, a seven-week sprint that stretched my creativity and technical skills. During this time, I built impactful projects, including:</p>\n<ul>\n<li><strong>Flashcard SaaS</strong>: A platform leveraging OpenAI and Stripe to make learning seamless and effective.</li>\n<li><strong>InternSim</strong>: A groundbreaking simulation tool for aspiring developers to gain hands-on experience through AI-powered projects.</li>\n<li><strong>Scraper</strong>: A data extraction tool designed for efficiency and practicality.</li>\n</ul>\n<p>These projects were not startups but exercises in rapid prototyping and problem-solving, teaching me the value of quick execution and collaboration.</p>\n<hr>\n<h2>Relocating for Growth and Security</h2>\n<p>One of the most significant decisions I made this year was moving from <strong>Somalia</strong> to <strong>Kenya</strong>. The decision was fueled by security concerns and the need for a stable environment to focus on my work. The move was challenging, bringing with it moments of doubt and difficulty, but it was a necessary step toward a brighter future.</p>\n<hr>\n<h2>Facing Adversity and Personal Growth</h2>\n<p>2024 wasn’t without its share of challenges. I faced numerous negative situations, from professional setbacks to personal struggles. At some point in the year, I was dealing with <strong>imposter syndrome</strong> a feeling that I wasn’t qualified for the expectations people had of me in terms of tech. This inner battle made me question my abilities and whether I truly deserved the recognition I was receiving.</p>\n<p>One of the biggest lessons I’ve learned is that <strong>living by other people’s expectations will never bring peace</strong>. Trying to meet everyone else’s standards only deepened my insecurities. Overcoming this required a shift in perspective:</p>\n<ul>\n<li><strong>Focusing on my own growth</strong> and recognizing my achievements for what they are.</li>\n<li>Accepting that I don’t have to meet anyone’s expectations but my own.</li>\n<li>Understanding that it’s okay to feel unsure at times, as long as I keep learning and improving.</li>\n</ul>\n<p>These lessons became the foundation for reclaiming my confidence and inner peace.</p>\n<hr>\n<h2>A Major Shift: Starting Over</h2>\n<p>As the year came to a close, I had a moment of clarity after watching a <strong>Starter Story video</strong> that challenged me to rethink my approach. I decided to <strong>close all my previous projects</strong> and start over with a clean slate.</p>\n<p>This reset marked the beginning of <a href="https://lamatools.com/"><strong>Lama Tools</strong></a>, an AI tools development agency with a mission to create practical, cutting-edge solutions. The shift wasn’t just about starting a new project, it was about building a future aligned with my values and long-term goals. It symbolized a fresh chapter, fueled by the lessons and growth from the past year.</p>\n<hr>\n<h2>Looking Forward: My Vision for 2025</h2>\n<p>As I step into 2025, I’m driven by a clear set of goals that reflect the lessons learned this year:</p>\n<ol>\n<li><strong>Learning to Say "No"</strong>: Setting boundaries and focusing on what truly matters.</li>\n<li><strong>Financial Discipline</strong>: Avoiding unnecessary spending and investing in meaningful growth.</li>\n<li><strong>Mastering AI Agentics</strong>: Diving deep into multi-agent systems and their applications.</li>\n<li><strong>Scaling Lama Tools</strong>: Working to reach or get closer to $10K MRR and establishing Lama Tools as a go-to agency for AI-powered solutions.</li>\n<li><strong>Living on My Own Terms</strong>: Letting go of others’ expectations and finding peace in pursuing what I truly value.</li>\n<li><strong>Starting Content Creation</strong>: Sharing my journey, lessons, and technical expertise through platforms like YouTube and blogs to inspire and connect with a wider audience.</li>\n</ol>\n<hr>\n<h2>A Year of Growth and Purpose (Conclusion )</h2>\n<p>2024 was a year of growth, filled with highs and lows. It was a year where I learned to adapt, to let go of what wasn’t serving me, and to embrace new opportunities. The lessons I’ve learned, especially the importance of living on my own terms, will guide me as I continue this journey.</p>\n<p>As I look forward to 2025, I’m excited to build on this foundation, turning challenges into achievements and dreams into reality.</p>\n<p>Here’s to resilience, focus, and chasing big goals! \uD83D\uDE80</p>\n'},{slug:"openai-advanced-voice-model-deep-dive",frontmatter:{title:"OpenAI's Advanced Voice Mode: A Deep Dive and Somali Language Test",date:"2024-09-28",readingTime:"7 min read"},contentHtml:'<p>In this post, we\'re going to explore OpenAI\'s new <strong>Advanced Voice Mode (AVM)</strong>, focusing on its capabilities, limitations, and how it performs in <strong>Somali language</strong> based on our tests. I teamed up with <strong>Muhammad</strong> (<a href="https://www.linkedin.com/in/muhaksim/">@muhaksim</a>) to put this new mode through its paces, and we came away with some interesting findings!</p>\n<hr>\n<h2>What is OpenAI\'s Advanced Voice Mode?</h2>\n<p>OpenAI\'s Advanced Voice Mode is a newly launched feature in ChatGPT designed to enhance the conversational experience through more natural and interactive voice communication. It\'s part of the latest innovations in natural language processing, designed to recognize and produce speech across multiple languages.</p>\n<h3>Key Aspects of AVM:</h3>\n<ul>\n<li><strong>Launch and Availability</strong>: Rolled out to ChatGPT Plus and Teams subscribers on September 24, 2024. Plans to extend to Enterprise and Edu customers soon, but currently unavailable in several regions, including the EU and UK.</li>\n<li><strong>New Interface</strong>: Features a blue animated sphere instead of the previous black dots, making interactions more engaging.</li>\n<li><strong>Voice Options</strong>: Introduces five new voices (Arbor, Maple, Sol, Spruce, and Vale), bringing the total to nine.</li>\n<li><strong>Technology</strong>: Built on GPT-4\'s audio capabilities, allowing for real-time conversations that can pick up on non-verbal cues.</li>\n</ul>\n<hr>\n<h2>Key Features of AVM</h2>\n<ol>\n<li><strong>Natural Conversations</strong>: Capable of understanding speech speed and emotional tone, creating more dynamic interactions.</li>\n<li><strong>Multilingual support</strong>: Effortlessly switches between languages like English and Somali.</li>\n<li><strong>Real-time adaptation</strong>: Learns on the fly, adjusting pronunciations and improving based on feedback.</li>\n<li><strong>Customization</strong>: Allows personalization through Custom Instructions and Memory features (though not fully integrated yet).</li>\n<li><strong>Interactive learning</strong>: Adapts to specific pronunciations and learning patterns.</li>\n</ol>\n<blockquote>\n<p><strong>Screenshot 1</strong>: <img src="/imgs/multi.jpeg" alt="Multilingual Switching"></p>\n</blockquote>\n<hr>\n<h2>Our Test: Performance in Somali</h2>\n<h3>\uD83C\uDF1F <strong>What We Liked</strong></h3>\n<ol>\n<li><strong>Effortless Language Switching</strong>: Smooth transitions between Somali and English.</li>\n<li><strong>Learning Capability</strong>: Quickly adapted to pronunciation corrections, like the Somali letter "C."</li>\n<li><strong>Text Generation</strong>: Excellent GPT-4-powered text generation in Somali, with high fluency and coherence.</li>\n</ol>\n<blockquote>\n<p><strong>Screenshot 2</strong>: <img src="/imgs/story.jpeg" alt="Somali Text Generation"></p>\n</blockquote>\n<h3>\uD83D\uDEA9 <strong>Areas for Improvement</strong></h3>\n<ol>\n<li><strong>Transcription Accuracy</strong>: Inconsistent at times, especially with random characters or words.</li>\n<li><strong>Pronunciation Challenges</strong>:\n<ul>\n<li>Mispronunciation of Somali letters like "X" and "C."</li>\n</ul>\n</li>\n</ol>\n<hr>\n<h2>Improvements We Hope to See</h2>\n<ul>\n<li><strong>Enhanced Transcription</strong>: Especially for non-Western languages like Somali.</li>\n<li><strong>Better Handling of Complex Phonetics</strong>: Improved pronunciation of language-specific sounds.</li>\n<li><strong>Persistent Learning</strong>: Ability to retain learned pronunciations across multiple sessions.</li>\n</ul>\n<hr>\n<h2>Technical Insights and Limitations</h2>\n<ul>\n<li><strong>Usage Limits</strong>: Subscribers may face restrictions on daily voice interaction time.</li>\n<li><strong>Regional Availability</strong>: Not yet available in all regions, notably absent in the EU and UK.</li>\n<li><strong>Ongoing Improvements</strong>: OpenAI claims enhancements in accent understanding and conversation fluidity since alpha testing.</li>\n</ul>\n<hr>\n<h2>Final Thoughts</h2>\n<p>The Advanced Voice Mode represents a significant leap in making AI interactions more intuitive and engaging. While there are still challenges, particularly with languages like Somali, the progress is exciting. Future iterations will likely address current limitations, making it even more robust for diverse language applications.</p>\n<blockquote>\n<p><strong>Screenshot 3</strong>: <img src="/imgs/teach.jpeg" alt="Learning Pronunciations"></p>\n</blockquote>\n<hr>\n<h2>Special Thanks</h2>\n<p>A special thanks to <strong>Muhammed Khasim</strong> for his invaluable insights and feedback during our testing of OpenAI\'s Advanced Voice Mode.</p>\n<h2>Watch Our Test on YouTube</h2>\n<p>We recorded our test of AVM in action. Check out the full video here:</p>\n<p><a href="https://youtu.be/cmzi7sdWzSc"><img src="/imgs/yt.png" alt="Watch on YouTube"></a></p>\n<hr>\n<p>Remember, while AVM feels almost human-like in its interactions, it\'s important to note that it doesn\'t possess genuine emotions or consciousness. It\'s a sophisticated algorithm designed to interpret and respond to user inputs in a natural, conversational manner.</p>\n'},{slug:"web-scraping-playwright-node",frontmatter:{title:"Web Scraping with Playwright and Node.js: A Practical Tutorials",date:"2024-08-24",readingTime:"8 min read"},contentHtml:"<p><img src=\"/imgs/web-scraping.png\" alt=\"alt text\">\nWeb scraping is an essential technique in a developer's toolkit, allowing the extraction of data from websites for various purposes, such as data analysis, monitoring, and automation. Playwright, paired with Node.js, provides a powerful and flexible framework for web scraping, especially when dealing with modern, dynamic websites. In this tutorial, we'll walk you through setting up a web scraping project with Playwright and cover essential aspects of scraping, from basic setups to handling more complex scenarios.</p>\n<h3>1. Setting Up Your Environment</h3>\n<p>To begin, you'll need to have Node.js installed on your machine. Node.js is a JavaScript runtime that allows you to run JavaScript code outside of a web browser. Once you have Node.js installed, you can create a new project directory and initialize a Node.js project:</p>\n<pre><code class=\"language-bash\">mkdir playwright-scraper\ncd playwright-scraper\nnpm init -y\nnpm install playwright\n</code></pre>\n<p>The commands above will create a new directory, initialize a Node.js project, and install Playwright. Playwright is a Node.js library to automate Chromium, Firefox, and WebKit with a single API. It is ideal for scraping tasks because of its ability to handle complex web interactions, including those involving JavaScript and dynamic content.</p>\n<h3>2. Writing Your First Playwright Script</h3>\n<p>Let's start by writing a simple script that launches a browser, navigates to a webpage, and retrieves the page title. Create a new file named <code>scraper.js</code> and add the following code:</p>\n<pre><code class=\"language-javascript\">const { chromium } = require('playwright');\n\n(async () => {\n  const browser = await chromium.launch();\n  const page = await browser.newPage();\n  await page.goto('https://example.com');\n  const title = await page.title();\n  console.log(`Title: ${title}`);\n  await browser.close();\n})();\n</code></pre>\n<p>In this script, we use Playwright to launch a Chromium browser, open a new page, navigate to \"<a href=\"https://example.com\">https://example.com</a>\", and print the page's title to the console. Finally, the browser is closed. This is a basic example, but it showcases the simplicity and power of Playwright for web scraping.</p>\n<h3>3. Extracting Data from a Web Page</h3>\n<p>Web scraping often involves extracting specific pieces of data from a webpage. Let's modify our script to extract the headlines from the Hacker News homepage. Update your <code>scraper.js</code> file with the following code:</p>\n<pre><code class=\"language-javascript\">await page.goto('https://news.ycombinator.com/');\nconst headlines = await page.$$eval('.storylink', links => links.map(link => link.textContent));\nconsole.log(headlines);\n</code></pre>\n<p>Here, we're using the <code>$$eval</code> function, which allows us to select all elements matching a CSS selector (<code>.storylink</code> in this case) and run a function on them. The function extracts the text content of each element and returns it as an array of strings.</p>\n<h3>4. Handling Dynamic Content</h3>\n<p>Modern websites often load content dynamically using JavaScript, which means that the content may not be available immediately when the page loads. Playwright's <code>waitForSelector</code> method can be used to wait for specific elements to appear before interacting with them:</p>\n<pre><code class=\"language-javascript\">await page.goto('https://example.com');\nawait page.waitForSelector('.dynamic-content');\nconst content = await page.$eval('.dynamic-content', el => el.textContent);\nconsole.log(content);\n</code></pre>\n<p>In this example, we wait for an element with the class <code>.dynamic-content</code> to appear on the page before extracting its text content.</p>\n<h3>5. Managing Authentication</h3>\n<p>Some websites require users to log in before accessing certain data. Playwright can handle this by filling out login forms and submitting them:</p>\n<pre><code class=\"language-javascript\">await page.goto('https://example.com/login');\nawait page.fill('#username', 'yourUsername');\nawait page.fill('#password', 'yourPassword');\nawait page.click('#loginButton');\n</code></pre>\n<p>This script navigates to a login page, fills out the username and password fields, and clicks the login button. Playwright will manage the session automatically, allowing you to scrape protected content.</p>\n<h3>6. Saving Scraped Data</h3>\n<p>Once you've extracted data from a webpage, you'll often want to save it for later use. You can save data to a JSON file using Node.js's built-in <code>fs</code> module:</p>\n<pre><code class=\"language-javascript\">const fs = require('fs');\nfs.writeFileSync('headlines.json', JSON.stringify(headlines, null, 2));\n</code></pre>\n<p>This code saves the <code>headlines</code> array to a file named <code>headlines.json</code>, formatting the JSON with an indentation of 2 spaces.</p>\n<h3>7. Best Practices for Web Scraping</h3>\n<p>When scraping websites, it's important to follow best practices to avoid legal issues or being blocked by the website. Here are some tips:</p>\n<ul>\n<li><strong>Respect <code>robots.txt</code>:</strong> Always check the site's <code>robots.txt</code> file to see what parts of the site you're allowed to scrape.</li>\n<li><strong>Rate Limiting:</strong> Introduce delays between requests to avoid overwhelming the server.</li>\n<li><strong>Error Handling:</strong> Implement error handling to manage issues such as network errors or unexpected changes in the webpage structure.</li>\n</ul>\n<h3>Conclusion</h3>\n<p>Web scraping with Playwright and Node.js offers a powerful way to collect data from websites, whether they are static or dynamically loaded. With the basics covered in this tutorial, you should be well-equipped to start building your own web scrapers. From handling simple HTML pages to complex, JavaScript-heavy sites requiring authentication, Playwright provides the tools you need to get the job done efficiently.</p>\n<p>Happy scraping!</p>\n"}];async function s(){return i.map(e=>`${e.slug}.md`).map(e=>({slug:e.replace(".md","")}))}async function r({params:e}){let{slug:t}=e,{contentHtml:n,frontmatter:s}=function(e){let t=e.replace(/\.md$/,""),n=i.find(e=>e.slug===t);if(!n)throw Error(`Post not found: ${t}`);return n}(t);return(0,a.jsxs)("main",{className:"mx-auto max-w-3xl space-y-6 px-4 pb-8 pt-10 sm:px-6",children:[a.jsx(o.default,{href:"/blog",className:"inline-block font-mono text-xs uppercase tracking-[0.2em] text-ink/50 transition-colors hover:text-clay",children:"← Back to writing"}),(0,a.jsxs)("div",{children:[(0,a.jsxs)("div",{className:"font-mono text-xs uppercase tracking-[0.2em] text-ink/40",children:[s.date," \xb7 ",s.readingTime]}),a.jsx("h1",{className:"mt-1 text-2xl leading-tight sm:text-3xl",children:s.title})]}),a.jsx("article",{className:"prose max-w-none prose-headings:text-ink prose-p:text-ink/80 prose-a:text-clay prose-strong:text-ink prose-code:text-clay prose-code:before:content-none prose-code:after:content-none",dangerouslySetInnerHTML:{__html:n}})]})}},7371:(e,t,n)=>{"use strict";n.d(t,{default:()=>o.a});var a=n(1812),o=n.n(a)},1812:(e,t,n)=>{"use strict";let{createProxy:a}=n(8570);e.exports=a("/home/abmoallim/Documents/abmoallim/node_modules/next/dist/client/link.js")},7481:(e,t,n)=>{"use strict";n.r(t),n.d(t,{default:()=>o});var a=n(6621);let o=e=>[{type:"image/x-icon",sizes:"150x150",url:(0,a.fillMetadataSegment)(".",e.params,"favicon.ico")+""}]},4998:(e,t,n)=>{"use strict";n.r(t),n.d(t,{default:()=>o});var a=n(6621);let o=e=>[{type:"image/png",sizes:"150x150",url:(0,a.fillMetadataSegment)(".",e.params,"icon.png")+"?02db24294edd3330"}]}};var t=require("../../../webpack-runtime.js");t.C(e);var n=e=>t(t.s=e),a=t.X(0,[948,977,621,321],()=>n(7006));module.exports=a})();